SELECT [qSoloVend-PerGriglieAgenti].[Salesperson Code], [qSoloVend-PerGriglieAgenti].Salesperson, [qSoloVend-PerGriglieAgenti].[Sell-to Customer No_], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].City, [qSoloVend-PerGriglieAgenti].[Current Risk], [qSoloVend-PerGriglieAgenti].[trademark code], [qSoloVend-PerGriglieAgenti].[season code], [qSoloVend-PerGriglieAgenti].[Payment Method Code], [qSoloVend-PerGriglieAgenti].[Payment Terms Code], [qSoloVend-PerGriglieAgenti].ScontoFattura, [qSoloVend-PerGriglieAgenti].ContoVendita, [qSoloVend-PerGriglieAgenti].PercentualeDirittoAlReso, Sum([qSoloVend-PerGriglieAgenti].PairsSold) AS PairsSold, Sum(Format$([ValueSold],"Currency")) AS ValueSold_, Sum(Format$([ValueSoldVAT],"Standard")) AS ValueSoldVAT_, "" AS [NOTE], Min([qSoloVend-PerGriglieAgenti].[requested delivery date]) AS [requested delivery date]
FROM [qSoloVend-PerGriglieAgenti]
GROUP BY [qSoloVend-PerGriglieAgenti].[Salesperson Code], [qSoloVend-PerGriglieAgenti].Salesperson, [qSoloVend-PerGriglieAgenti].[Sell-to Customer No_], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].City, [qSoloVend-PerGriglieAgenti].[Current Risk], [qSoloVend-PerGriglieAgenti].[trademark code], [qSoloVend-PerGriglieAgenti].[season code], [qSoloVend-PerGriglieAgenti].[Payment Method Code], [qSoloVend-PerGriglieAgenti].[Payment Terms Code], [qSoloVend-PerGriglieAgenti].ScontoFattura, [qSoloVend-PerGriglieAgenti].ContoVendita, [qSoloVend-PerGriglieAgenti].PercentualeDirittoAlReso, ""
HAVING ((([qSoloVend-PerGriglieAgenti].[Salesperson Code])=[forms]![principale]![filtroAgentePerGrigliaAgenti]) AND (([qSoloVend-PerGriglieAgenti].[season code])=[forms]![principale]![creditofiltrostagione2]))
ORDER BY [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[trademark code];

